const body = $json.body || $json;
const ALLOWED_OPS = new Set(['issue', 'void', 'allowance', 'voidAllowance', 'query']);
for (const k of ['capability', 'provider', 'op', 'input']) if (body[k] === undefined) throw new Error(k + ' required');
if (!ALLOWED_OPS.has(body.op)) throw new Error('op must be one of: ' + [...ALLOWED_OPS].join(', '));
// Map op → endpoint path (matches svc /v1/* routes)
const opEndpoint = {
  issue: '/v1/issue',
  void: '/v1/void',
  allowance: '/v1/allowance',
  voidAllowance: '/v1/void-allowance',
  query: '/v1/query'
};
return [{ json: {
  correlationId: `inv-gate-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  startedAt: new Date().toISOString(),
  capability: body.capability,
  provider: body.provider,
  op: body.op,
  opEndpoint: opEndpoint[body.op],
  input: body.input
}}];

const state = $('Stamp + validate gate').first().json;
const statusCode = Number($json.statusCode ?? 0);
const respBody = $json.body ?? $json;
if (statusCode === 400 && respBody?.error?.code === 'UNKNOWN_PROVIDER') {
  return [{ json: { ...state, gateOk: false, errorCode: 'UNKNOWN_PROVIDER', supportedCapabilities: null } }];
}
if (statusCode < 200 || statusCode >= 300) {
  return [{ json: { ...state, gateOk: false, errorCode: 'CAPABILITY_LOOKUP_FAILED', upstreamStatus: statusCode } }];
}
const caps = Array.isArray(respBody?.capabilities) ? respBody.capabilities : [];
const supported = caps.includes(state.capability);
return [{ json: { ...state, gateOk: supported, errorCode: supported ? null : 'UNSUPPORTED_CAPABILITY', supportedCapabilities: caps } }];

const state = $('Decide: supported?').first().json;
const statusCode = Number($json.statusCode ?? 0);
const respBody = $json.body ?? $json;
const ok = statusCode >= 200 && statusCode < 300;
return [{ json: {
  ...state,
  ok,
  statusCode,
  result: ok ? respBody?.result : null,
  error: ok ? null : respBody?.error,
  appliedAt: new Date().toISOString()
}}];
